47	// NewPreClaimIntakeHook constructs the bead-intake complexity gate used
48	// before claim in the work / execute-loop paths. The hook evaluates the bead
49	// using the repository's triage prompt and returns one of the typed intake
50	// outcomes so the loop can decide whether to claim or skip the candidate.
51	//
52	// The hook preserves operator-supplied passthrough constraints. When the
53	// resolved route cannot satisfy the strong splitter floor, it returns an
54	// actionable-but-blocking result with agent_power_unsatisfied in the detail so
55	// the loop can skip the bead instead of attempting weak decomposition.
56	func NewPreClaimIntakeHook(projectRoot string, store BeadReader, rcfg config.ResolvedConfig, svc agentlib.FizeauService, runner AgentRunner) func(ctx context.Context, beadID string) (PreClaimIntakeResult, error) {
57		return func(ctx context.Context, beadID string) (PreClaimIntakeResult, error) {
58			if ctx != nil {
59				if err := ctx.Err(); err != nil {
60					return PreClaimIntakeResult{}, err
61				}
62			}
63			if strings.TrimSpace(projectRoot) == "" {
64				return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: project root required")
65			}
66			if err := ensureBeadLifecycleSkill(projectRoot); err != nil {
67				return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: %w", err)
68			}
69			if store == nil {
70				return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: bead reader required")
71			}
72	
73			b, err := store.Get(beadID)
74			if err != nil {
75				return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: load bead %s: %w", beadID, err)
76			}
77	
78			prompt, err := buildPreClaimIntakePrompt(projectRoot, store, b)
79			if err != nil {
80				return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: build prompt: %w", err)
81			}
82	
83			strongMinPower := resolveStrongSplitterMinPower(ctx, projectRoot, svc)
84			if rcfg.MinPower() > strongMinPower {
85				strongMinPower = rcfg.MinPower()
86			}
87	
88			runtime := AgentRunRuntime{
89				Prompt:          prompt,
90				WorkDir:         projectRoot,
91				PromptSource:    PreClaimIntakePromptSource,
92				ProfileOverride: "smart",
93				ClearMaxPower:   true,
94			}
95			if strongMinPower > 0 {
96				runtime.MinPowerOverride = strongMinPower
97			}
98			payload, err := dispatchPreClaimIntakePayload(ctx, projectRoot, svc, runner, rcfg, runtime, strongMinPower)
99			if err != nil {
100				if isStrongPowerUnsatisfiedError(err) {
101					return PreClaimIntakeResult{
102						Outcome: PreClaimIntakeAmbiguousNeedsHuman,
103						Detail:  "pre-claim intake requires a smart/frontier route but no viable model was available",
104					}, nil
105				}
106				return PreClaimIntakeResult{}, err
107			}
108	
109			var out preClaimIntakePromptResult
110			if err := json.Unmarshal([]byte(payload), &out); err != nil {
111				return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: decode result: %w", err)
112			}
113	
114			switch strings.ToLower(strings.TrimSpace(out.Classification)) {
115			case "atomic":
116				return PreClaimIntakeResult{Outcome: PreClaimIntakeActionableAtomic, Detail: strings.TrimSpace(out.Reasoning)}, nil
117			case "rewritten":
118				return PreClaimIntakeResult{
119					Outcome: PreClaimIntakeActionableButRewritten,
120					Detail:  strings.TrimSpace(out.Reasoning),
121					Rewrite: PreClaimIntakeRewrite{
122						Description:   strings.TrimSpace(out.Rewrite.Description),
123						Acceptance:    strings.TrimSpace(out.Rewrite.Acceptance),
124						ChangedFields: normalizePreClaimIntakeRewriteFields(out.Rewrite.ChangedFields),
125					},
126				}, nil
127			case "decomposable":
128				return PreClaimIntakeResult{Outcome: PreClaimIntakeTooLargeDecomposed, Detail: strings.TrimSpace(out.Reasoning)}, nil
129			case "ambiguous":
130				return PreClaimIntakeResult{Outcome: PreClaimIntakeAmbiguousNeedsHuman, Detail: strings.TrimSpace(out.Reasoning)}, nil
131			case "":
132				return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: missing classification")
133			default:
134				return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: unknown classification %q", out.Classification)
135			}
136		}
137	}
