139	func dispatchPreClaimIntakePayload(ctx context.Context, projectRoot string, svc agentlib.FizeauService, runner AgentRunner, rcfg config.ResolvedConfig, runtime AgentRunRuntime, strongMinPower int) (string, error) {
140		payload, err := dispatchPreClaimIntakePayloadOnce(ctx, projectRoot, svc, runner, rcfg, runtime)
141		if err == nil {
142			return payload, nil
143		}
144		if runtime.ProfileOverride != "smart" || strongMinPower > 0 || !isSmartProfileUnavailableError(err) {
145			return "", err
146		}
147	
148		runtime.ProfileOverride = DefaultRoutingProfile
149		return dispatchPreClaimIntakePayloadOnce(ctx, projectRoot, svc, runner, rcfg, runtime)
150	}
