160	func buildPreClaimIntakePrompt(projectRoot string, store BeadReader, b *bead.Bead) (string, error) {
161		env := preClaimIntakePromptEnvelope{
162			Title:         strings.TrimSpace(b.Title),
163			Description:   strings.TrimSpace(b.Description),
164			Acceptance:    strings.TrimSpace(b.Acceptance),
165			Labels:        append([]string(nil), b.Labels...),
166			PriorAttempts: []preClaimIntakeAttempt{},
167			Depth:         beadDecompositionDepth(projectRoot, b),
168			Parent:        strings.TrimSpace(b.Parent),
169			Dependencies:  append([]string(nil), b.DepIDs()...),
170		}
171	
172		// Prior attempts are optional for the gate. If bead history is available,
173		// include the last few attempt/result summaries to help the classifier
174		// distinguish a first-pass atomic bead from repeated decomposition.
175		if store != nil {
176			if eventStore, ok := any(store).(interface {
177				Events(id string) ([]bead.BeadEvent, error)
178			}); ok {
179				if events, err := eventStore.Events(b.ID); err == nil && len(events) > 0 {
180					for i := len(events) - 1; i >= 0 && len(env.PriorAttempts) < 5; i-- {
181						ev := events[i]
182						if ev.Kind != "bead.result" && ev.Kind != "execute-bead" {
183							continue
184						}
185						env.PriorAttempts = append(env.PriorAttempts, preClaimIntakeAttempt{
186							Status:    strings.TrimSpace(ev.Summary),
187							Rationale: strings.TrimSpace(ev.Body),
188						})
189					}
190				}
191			}
192		}
193	
194		body, err := json.MarshalIndent(env, "", "  ")
195		if err != nil {
196			return "", err
197		}
198	
199		var sb strings.Builder
200		sb.WriteString("MODE: intake\n")
201		sb.WriteString("You are evaluating whether this bead is atomic, decomposable, ambiguous, or safely refinable before claim.\n")
202		sb.WriteString("Use rewritten only when you can preserve the bead's intent and return safe description/acceptance updates without inventing behavior, choosing product semantics, widening scope, or dropping acceptance criteria.\n")
203		sb.WriteString("If the bead cannot be safely refined, classify it as ambiguous.\n")
204		sb.WriteString("Return exactly one JSON object matching the intake schema with classification, confidence, reasoning, and optional rewrite fields.\n")
205		sb.WriteString("When classification is rewritten, include rewrite.changed_fields, rewrite.description, and rewrite.acceptance.\n")
206		sb.WriteString("Do not include prose or markdown.\n\n")
207		sb.WriteString("```json\n")
208		sb.Write(body)
209		sb.WriteString("\n```\n")
210		return sb.String(), nil
211	}
