213	func intakeResultPayload(result *Result) (string, error) {
214		if result == nil {
215			return "", fmt.Errorf("pre-claim intake: empty runner result")
216		}
217		text := strings.TrimSpace(result.CondensedOutput)
218		if text == "" {
219			text = strings.TrimSpace(result.Output)
220		}
221		if text == "" {
222			if strings.TrimSpace(result.Error) != "" {
223				return "", fmt.Errorf("pre-claim intake: runner error: %s", strings.TrimSpace(result.Error))
224			}
225			if result.ExitCode != 0 {
226				return "", fmt.Errorf("pre-claim intake: runner exited with code %d and empty output", result.ExitCode)
227			}
228			return "", fmt.Errorf("pre-claim intake: empty output")
229		}
230		candidate, ok := extractJSONCandidate(text)
231		if !ok {
232			return "", fmt.Errorf("pre-claim intake: no JSON object found")
233		}
234		return candidate, nil
235	}
