237	func normalizePreClaimIntakeRewriteFields(fields []string) []string {
238		if len(fields) == 0 {
239			return nil
240		}
241		seen := make(map[string]struct{}, len(fields))
242		out := make([]string, 0, len(fields))
243		for _, field := range fields {
244			field = strings.ToLower(strings.TrimSpace(field))
245			if field == "" {
246				continue
247			}
248			if _, ok := seen[field]; ok {
249				continue
250			}
251			seen[field] = struct{}{}
252			out = append(out, field)
253		}
254		return out
255	}
